// Camera.h
#pragma once

#include <glm/glm.hpp>

class Camera {
public:
  Camera(float aspectRatio, float fovY = 45.0f, float nearPlane = 0.1f, float farPlane = 100.f);

  glm::mat4 GetViewMatrix() const;
  glm::mat4 GetProjectionMatrix() const;

  void Move(const glm::vec3& delta);
  void Rotate(const glm::vec3& deltaEulerAngles);

private:
  glm::vec3 position_;
  glm::vec3 rotation_; // Euler angles, pitch, yaw, roll in degrees

  float aspectRatio_;
  float fovY_;
  float nearPlane_;
  float farPlane_;
};

// Camera.cpp
#include "Camera.h"
#include <glm/gtc/matrix_transform.hpp>

Camera::Camera(float aspectRatio, float fovY, float nearPlane, float farPlane)
  : position_(glm::vec3(0.0f, 0.0f, 3.0f)), rotation_(glm::vec3(0.0f, 0.0f, 0.0f)),
    aspectRatio_(aspectRatio), fovY_(fovY), nearPlane_(nearPlane), farPlane_(farPlane) {
}

glm::mat4 Camera::GetViewMatrix() const {
  glm::mat4 view = glm::mat4(1.0f);
  view = glm::rotate(view, glm::radians(rotation_.x), glm::vec3(1.0f, 0.0f, 0.0f));
  view = glm::rotate(view, glm::radians(rotation_.y), glm::vec3(0.0f, 1.0f, 0.0f));
  view = glm::rotate(view, glm::radians(rotation_.z), glm::vec3(0.0f, 0.0f, 1.0f));
  view = glm::translate(view, -position_);
  return view;
}

glm::mat4 Camera::GetProjectionMatrix() const {
  return glm::perspective(glm::radians(fovY_), aspectRatio_, nearPlane_, farPlane_);
}

void Camera::Move(const glm::vec3& delta) {
  position_ += delta;
}

void Camera::Rotate(const glm::vec3& deltaEulerAngles) {
  rotation_ += deltaEulerAngles;
}
